import torch
import torch.nn.functional as F
from scipy.optimize import minimize_scalar

def temperature_scaling_calibration(
    logits: torch.Tensor,   # (N, K) validation logits
    y_true: torch.Tensor,   # (N,) true class indices
) -> float:
    """Find the temperature T that minimises log loss on the validation set."""

    def nll_at_temperature(T):
        scaled = logits / T
        return F.cross_entropy(scaled, y_true).item()

    result = minimize_scalar(nll_at_temperature, bounds=(0.01, 10.0), method='bounded')
    return result.x  # optimal temperature

# T < 1 → model was overconfident (sharpen less) → calibration pushes T up
# T > 1 → model was underconfident (too spread) → calibration sharpens logits

# After finding T_opt, apply at inference:
def calibrated_probs(logits: torch.Tensor, T: float) -> torch.Tensor:
    return F.softmax(logits / T, dim=-1)
